xpath.script:
const _announcements = ;
const _links = ;

const _linksByAnnouncement = {};
_links.forEach(l => {
    const aid = l.x_studio_announcement_id[0];
    if (!_linksByAnnouncement[aid]) _linksByAnnouncement[aid] = [];
    _linksByAnnouncement[aid].push({ text: l.x_studio_display_text, href: l.x_studio_href });
});

var OdooAnnouncements = _announcements.map(a => ({
    headline: a.x_studio_headline,
    sub: a.x_studio_subtitle,
    mediaLink: a.x_studio_media_link,
    isVideo: a.x_studio_is_video,
    links: _linksByAnnouncement[a.id] || []
}));
